import { describe, it, expect } from 'vitest'
import { buildFullBody } from '../post-xhs.js'

describe('buildFullBody', () => {
  it('appends hashtags to body', () => {
    const result = buildFullBody('秋天来了，皮肤容易干燥...', ['护肤', '秋季'])
    expect(result).toContain('秋天来了')
    expect(result).toContain('#护肤')
    expect(result).toContain('#秋季')
  })

  it('joins multiple tags with spaces', () => {
    const result = buildFullBody('body text', ['tag1', 'tag2'])
    expect(result).toContain('#tag1')
    expect(result).toContain('#tag2')
  })
})
